#!/usr/bin/env python3
"""
Build a clean production deploy folder with flows.yaml preset from production_paths.yaml.

Usage:
  cp config/production_paths.example.yaml config/production_paths.yaml
  # edit production_paths.yaml with your paths
  python scripts/prepare_production_bundle.py

Options:
  --purge-server-dirs   Empty purge_on_server directories (run on Windows server).
  --purge-local-data    Remove files under ./data in the bundle (keeps .gitkeep).
"""

from __future__ import annotations

import argparse
import re
import shutil
import sys
from pathlib import Path

import yaml

ROOT = Path(__file__).resolve().parents[1]
PRODUCTION_PATHS = ROOT / "config" / "production_paths.yaml"
EXAMPLE_PATHS = ROOT / "config" / "production_paths.example.yaml"

COPY_DIRS = ("file_processor", "examples", "offline", "config", "scripts")
COPY_FILES = (
    "pyproject.toml",
    "requirements.txt",
    "README.md",
    "INSTALL.md",
    "OPS_GUIDE.md",
    "WINDOWS_SERVICE_GUIDE.md",
)

SKIP_DIR_NAMES = {".git", ".venv", "__pycache__", ".egg-info", "dist", ".cursor"}
SKIP_FILE_PATTERNS = (
    re.compile(r"^~\$"),  # Excel lock files
    re.compile(r"\.pyc$"),
)


def _load_production_config() -> dict:
    path = PRODUCTION_PATHS if PRODUCTION_PATHS.exists() else EXAMPLE_PATHS
    if not path.exists():
        print(
            f"Missing {PRODUCTION_PATHS}. Copy {EXAMPLE_PATHS} and edit your paths.",
            file=sys.stderr,
        )
        sys.exit(1)
    return yaml.safe_load(path.read_text(encoding="utf-8"))


def _yaml_path(p: str) -> str:
    """Emit a path safely in YAML."""
    if "\\" in p or ":" in p:
        return "'" + p.replace("'", "''") + "'"
    return p


def _build_flows_yaml(cfg: dict) -> str:
    mapping_file = cfg.get("mapping_file", "./examples/mapping ROLLS SSW outgoing.xlsx")
    skeleton_xml = cfg.get("skeleton_xml", "./examples/skeleton_PldaSswDeclaration.xml")
    xsd_file = cfg.get("xsd_file", "./examples/PLDASSW.xsd")

    lines = [
        "# Generated by scripts/prepare_production_bundle.py — do not edit by hand.",
        "# Regenerate from config/production_paths.yaml",
        "",
        "flows:",
    ]

    for name, flow in cfg.get("flows", {}).items():
        mode = flow.get("mode", "csv_to_xml")
        lines.extend(
            [
                f"  - name: {name}",
                f"    mode: {mode}",
                "",
                f"    input_dir: {_yaml_path(flow['input_dir'])}",
                f"    success_dir: {_yaml_path(flow['success_dir'])}",
                f"    error_dir: {_yaml_path(flow['error_dir'])}",
                f"    archive_dir: {_yaml_path(flow['archive_dir'])}",
                f"    in_progress_dir: {_yaml_path(flow['in_progress_dir'])}",
                "",
                f"    file_glob: \"{flow.get('file_glob', '*.*')}\"",
                "",
                "    input_format: csv",
                f"    delimiter: \"{flow.get('delimiter', '|')}\"",
                "",
                f"    mapping_file: {mapping_file}",
                f"    mapping_sheet_name: \"{flow.get('mapping_sheet_name', '')}\"",
            ]
        )
        if mode == "csv_to_xml":
            lines.extend(
                [
                    f"    skeleton_xml: {skeleton_xml}",
                    f"    xsd_file: {xsd_file}",
                ]
            )
        else:
            lines.extend(
                [
                    "    skeleton_xml: null",
                    "    xsd_file: null",
                ]
            )
        lines.append(f"    root_element_name: {flow.get('root_element_name', 'PldaSswDeclaration')}")
        lines.append("")

    return "\n".join(lines) + "\n"


def _should_skip_path(path: Path) -> bool:
    for part in path.parts:
        if part in SKIP_DIR_NAMES or part.endswith(".egg-info"):
            return True
    if path.is_file():
        for pat in SKIP_FILE_PATTERNS:
            if pat.search(path.name):
                return True
    return False


def _copy_tree(src: Path, dst: Path) -> None:
    if _should_skip_path(src):
        return
    if src.is_dir():
        dst.mkdir(parents=True, exist_ok=True)
        for child in src.iterdir():
            _copy_tree(child, dst / child.name)
    else:
        dst.parent.mkdir(parents=True, exist_ok=True)
        shutil.copy2(src, dst)


def _purge_directory(dir_path: Path) -> int:
    if not dir_path.is_dir():
        return 0
    removed = 0
    for item in dir_path.iterdir():
        if item.name == ".gitkeep":
            continue
        if item.is_file():
            item.unlink()
            removed += 1
        elif item.is_dir():
            shutil.rmtree(item)
            removed += 1
    return removed


def _prepare_local_data(bundle: Path) -> None:
    """Empty dev data folders inside bundle; keep folder structure."""
    data = bundle / "data"
    if not data.exists():
        return
    for sub in data.rglob("*"):
        if sub.is_file() and sub.name != ".gitkeep":
            sub.unlink()


def prepare_bundle(
    output_dir: Path,
    *,
    purge_local_data: bool,
    purge_server_dirs: bool,
    cfg: dict,
) -> None:
    if output_dir.exists():
        shutil.rmtree(output_dir)
    output_dir.mkdir(parents=True)

    for name in COPY_DIRS:
        src = ROOT / name
        if src.exists():
            _copy_tree(src, output_dir / name)

    for name in COPY_FILES:
        src = ROOT / name
        if src.exists():
            shutil.copy2(src, output_dir / name)

    # Generated flows.yaml (overwrite copied config/flows.yaml)
    flows_yaml = _build_flows_yaml(cfg)
    (output_dir / "config" / "flows.yaml").write_text(flows_yaml, encoding="utf-8")
    # Keep example production paths in bundle for reference
    if PRODUCTION_PATHS.exists():
        shutil.copy2(PRODUCTION_PATHS, output_dir / "config" / "production_paths.yaml")

    if purge_local_data:
        _prepare_local_data(output_dir)
        print("Purged local ./data files in bundle (kept .gitkeep).")

    if purge_server_dirs:
        for raw in cfg.get("purge_on_server", []) or []:
            p = Path(raw)
            n = _purge_directory(p)
            print(f"Purged {n} item(s) from {p}")

    print(f"Production bundle ready: {output_dir.resolve()}")


def main() -> None:
    parser = argparse.ArgumentParser(description="Prepare FileProcessor production deploy folder.")
    parser.add_argument(
        "--output",
        type=Path,
        default=None,
        help="Output directory (default: bundle_output_dir from production_paths.yaml)",
    )
    parser.add_argument(
        "--purge-local-data",
        action="store_true",
        help="Remove test files from data/ inside the bundle.",
    )
    parser.add_argument(
        "--purge-server-dirs",
        action="store_true",
        help="Empty purge_on_server dirs (run on Windows where those paths exist).",
    )
    args = parser.parse_args()

    cfg = _load_production_config()
    out = args.output or Path(cfg.get("bundle_output_dir", "dist/FileProcessor_SSW"))
    if not out.is_absolute():
        out = ROOT / out

    prepare_bundle(
        out,
        purge_local_data=args.purge_local_data,
        purge_server_dirs=args.purge_server_dirs,
        cfg=cfg,
    )


if __name__ == "__main__":
    main()
